import { useCallback, useEffect, useRef } from 'react';

import { ORIENTATION } from '../../../../constants.js';
import { OVERLAY_ADDITIONAL_SIZE, OVERLAY_OFFSET } from '../constants.js';
import { useOrientation } from '../context/RangeLegendOrientationContext.js';
import { useLegendSegmentsOverlayHandlers } from '../hooks/use-legend-segments-overlay-handlers.js';

export const RangeLegendSegmentsOverlay = (props: {
  itemMarkers: number[];
}) => {
  const { itemMarkers } = props;

  const overlayRef = useRef<SVGRectElement>(null);

  const { onMouseLeaveHandler, onMouseMoveHandler } =
    useLegendSegmentsOverlayHandlers(itemMarkers);
  const { orientation } = useOrientation();
  const isVertical = orientation === ORIENTATION.Vertical;

  const overlaySizeHandler = useCallback(
    (legendBar: SVGSVGElement, overlayEl: SVGRectElement) => {
      const { height: legendHeight, width: legendWidth } =
        legendBar.getBoundingClientRect();

      const overlayHeight =
        legendHeight + (isVertical ? 0 : OVERLAY_ADDITIONAL_SIZE);
      const overlayY = isVertical ? 0 : -OVERLAY_OFFSET;
      const overlayWidth =
        legendWidth + (isVertical ? OVERLAY_ADDITIONAL_SIZE : 0);
      const overlayX = isVertical ? -OVERLAY_OFFSET : 0;

      overlayEl.setAttribute('y', overlayY.toString());
      overlayEl.setAttribute('x', overlayX.toString());
      overlayEl.setAttribute('height', overlayHeight.toString());
      overlayEl.setAttribute('width', overlayWidth.toString());
    },
    [isVertical],
  );

  useEffect(() => {
    if (overlayRef.current) {
      const legendBar = overlayRef.current.closest('svg')
        ?.previousElementSibling as SVGSVGElement;

      if (legendBar) {
        overlaySizeHandler(legendBar, overlayRef.current);

        const observer = new MutationObserver(() => {
          // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
          overlaySizeHandler(legendBar, overlayRef.current!);
        });

        observer.observe(legendBar, {
          attributes: true,
          childList: true,
          subtree: true,
          characterData: true,
        });

        return () => observer.disconnect();
      }
    }
  }, [overlaySizeHandler]);

  return (
    <rect
      ref={overlayRef}
      role="presentation"
      id="segments-overlay"
      fill="transparent"
      onMouseMove={onMouseMoveHandler}
      onMouseLeave={onMouseLeaveHandler}
    />
  );
};
